// Package main provides regression tests for Flipt authentication bugs.
package main

import (
	"context"
	"fmt"
	"net"
	"net/http"
	"net/http/httptest"
	"testing"
	"time"

	"github.com/grpc-ecosystem/grpc-gateway/v2/runtime"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
	authmiddlewaregrpc "go.flipt.io/flipt/internal/server/authn/middleware/grpc"
	authmiddlewarehttp "go.flipt.io/flipt/internal/server/authn/middleware/http"
	middlewarecommon "go.flipt.io/flipt/internal/server/authn/middleware/common"
	"go.flipt.io/flipt/internal/config"
	"go.flipt.io/flipt/internal/storage/authn"
	"go.flipt.io/flipt/internal/storage/authn/memory"
	authrpc "go.flipt.io/flipt/rpc/flipt/auth"
	"go.uber.org/zap/zaptest"
	"google.golang.org/grpc"
	"google.golang.org/grpc/metadata"
	"google.golang.org/grpc/reflection"
	"google.golang.org/protobuf/types/known/timestamppb"
)

// mockServer implements the SkipsAuthenticationServer interface for testing
type mockSkippableServer struct {
	grpc.UnaryServerInterceptor
	shouldSkip bool
}

func (s *mockSkippableServer) SkipsAuthentication(ctx context.Context) bool {
	return s.shouldSkip
}

// TestRegression_CookieTokenNotExtracted tests that HTTP cookies containing
// client tokens are not properly extracted and forwarded to the gRPC layer.
// This is a regression test for the bug where browser-based sessions fail
// because cookies are not properly handled by the authentication middleware.
func TestRegression_CookieTokenNotExtracted(t *testing.T) {
	// Setup authentication store with a valid token
	store := memory.NewStore()
	clientToken, _, err := store.CreateAuthentication(
		context.Background(),
		&authn.CreateAuthenticationRequest{Method: authrpc.Method_METHOD_TOKEN},
	)
	require.NoError(t, err)

	// Create gRPC server with ClientTokenAuthenticationInterceptor
	logger := zaptest.NewLogger(t)
	grpcServer := grpc.NewServer(
		grpc.ChainUnaryInterceptor(
			authmiddlewaregrpc.ClientTokenAuthenticationInterceptor(logger, store),
		),
	)
	reflection.Register(grpcServer)

	// Create test listener
	listener, err := net.Listen("tcp", "localhost:0")
	require.NoError(t, err)
	defer listener.Close()

	// Start gRPC server in background
	go func() {
		_ = grpcServer.Serve(listener)
	}()
	defer grpcServer.Stop()

	// Wait for server to be ready
	time.Sleep(100 * time.Millisecond)

	// Create gRPC client connection
	conn, err := grpc.NewClient(
		listener.Addr().String(),
		grpc.WithInsecure(),
	)
	require.NoError(t, err)
	defer conn.Close()

	// Test 1: Bearer token in Authorization header works
	t.Run("Authorization header with Bearer token succeeds", func(t *testing.T) {
		ctx := context.Background()
		ctx = metadata.AppendToOutgoingContext(ctx, "authorization", fmt.Sprintf("Bearer %s", clientToken))

		// Create a test unary call
		var resultAuth *authrpc.Authentication
		handler := func(ctx context.Context, req interface{}) (interface{}, error) {
			resultAuth = authmiddlewaregrpc.GetAuthenticationFrom(ctx)
			return nil, nil
		}

		interceptor := authmiddlewaregrpc.ClientTokenAuthenticationInterceptor(logger, store)
		_, err := interceptor(ctx, nil, &grpc.UnaryServerInfo{Server: &grpc.Server{}}, handler)

		// This should succeed
		assert.NoError(t, err)
		assert.NotNil(t, resultAuth)
	})

	// Test 2: Token in gRPC cookie header works
	t.Run("gRPC cookie header with flipt_client_token succeeds", func(t *testing.T) {
		ctx := context.Background()
		// Note: This is the expected format in gRPC metadata for cookies
		ctx = metadata.AppendToOutgoingContext(ctx, "grpcgateway-cookie", fmt.Sprintf("flipt_client_token=%s", clientToken))

		var resultAuth *authrpc.Authentication
		handler := func(ctx context.Context, req interface{}, _ *grpc.UnaryServerInfo, _ grpc.UnaryHandler) (interface{}, error) {
			resultAuth = authmiddlewaregrpc.GetAuthenticationFrom(ctx)
			return nil, nil
		}

		interceptor := authmiddlewaregrpc.ClientTokenAuthenticationInterceptor(logger, store)
		ctx = metadata.NewIncomingContext(ctx, metadata.MD{
			"grpcgateway-cookie": []string{fmt.Sprintf("flipt_client_token=%s", clientToken)},
		})

		_, err := interceptor(ctx, nil, &grpc.UnaryServerInfo{Server: &grpc.Server{}}, func(ctx context.Context, req interface{}) (interface{}, error) {
			resultAuth = authmiddlewaregrpc.GetAuthenticationFrom(ctx)
			return nil, nil
		})

		assert.NoError(t, err)
		assert.NotNil(t, resultAuth)
	})

	// Test 3: HTTP cookie forwarding has a bug
	// The ForwardCookies function in internal/server/authn/method/http.go has a bug
	// where it always uses stateCookieKey instead of the loop variable
	t.Run("HTTP cookie forwarding has bug - token cookie overwritten", func(t *testing.T) {
		// Create a mock HTTP request with both state and token cookies
		req := httptest.NewRequest("GET", "http://localhost/api/v1/flags", nil)
		req.AddCookie(&http.Cookie{
			Name:  "flipt_client_state",
			Value: "state_value_12345",
		})
		req.AddCookie(&http.Cookie{
			Name:  middlewarecommon.TokenCookieKey, // "flipt_client_token"
			Value: clientToken,
		})

		// Simulate what ForwardCookies should do but doesn't
		md := metadata.MD{}
		for _, key := range []string{"flipt_client_state", middlewarecommon.TokenCookieKey} {
			if cookie, err := req.Cookie(key); err == nil {
				// BUG: The actual code always uses stateCookieKey instead of key variable
				// This causes the second iteration to overwrite the first
				md["flipt_client_state"] = []string{cookie.Value} // Should be md[key]
			}
		}

		// The bug manifests as: the token cookie value overwrites the state cookie
		// So we end up with md["flipt_client_state"] = clientToken (wrong!)
		// instead of md["flipt_client_token"] = clientToken (correct)

		// Verify the bug exists
		stateCookieValues := md.Get("flipt_client_state")
		tokenCookieValues := md.Get(middlewarecommon.TokenCookieKey)

		// Due to the bug, stateCookieKey holds the token value
		assert.Equal(t, clientToken, stateCookieValues[0], "BUG: token value overwrites state cookie due to variable reuse")

		// And the token cookie is missing from metadata
		assert.Empty(t, tokenCookieValues, "BUG: token cookie is not properly stored in metadata")
	})
}

// TestRegression_NoServerAuthenticationBypass tests that there is no mechanism
// to skip authentication for specific HTTP servers when using the gRPC gateway.
// This affects internal servers (like OIDC callback handlers) that should not
// require authentication but are forced to go through the authentication middleware.
func TestRegression_NoServerAuthenticationBypass(t *testing.T) {
	logger := zaptest.NewLogger(t)
	store := memory.NewStore()

	// Test 1: gRPC server can skip auth via SkipsAuthenticationServer interface
	t.Run("gRPC server can skip auth with SkipsAuthenticationServer interface", func(t *testing.T) {
		skipServer := &mockSkippableServer{shouldSkip: true}

		handler := func(ctx context.Context, req interface{}) (interface{}, error) {
			auth := authmiddlewaregrpc.GetAuthenticationFrom(ctx)
			// When skipping auth, auth should be nil but no error
			assert.Nil(t, auth)
			return nil, nil
		}

		interceptor := authmiddlewaregrpc.ClientTokenAuthenticationInterceptor(logger, store)
		// Empty context, no authentication provided
		ctx := context.Background()

		// This should succeed because the server skips auth
		_, err := interceptor(ctx, nil, &grpc.UnaryServerInfo{Server: skipServer}, handler)
		assert.NoError(t, err)
	})

	// Test 2: HTTP middleware has no skip mechanism
	t.Run("HTTP middleware cannot skip auth for specific servers", func(t *testing.T) {
		httpMiddleware := authmiddlewarehttp.NewHTTPMiddleware(config.AuthenticationSession{
			Domain: "localhost",
		})

		// Create a handler that would need to skip auth (e.g., OIDC callback)
		innerHandler := http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			w.WriteHeader(http.StatusOK)
			w.Write([]byte("OK"))
		})

		// The HTTP middleware has no way to skip authentication for certain handlers
		// It only handles logout and error scenarios
		wrappedHandler := httpMiddleware.Handler(innerHandler)

		// Make a request to a normal endpoint (not logout)
		req := httptest.NewRequest("GET", "http://localhost/auth/v1/some/endpoint", nil)
		w := httptest.NewRecorder()

		wrappedHandler.ServeHTTP(w, req)

		// The middleware just passes through - there's no way to configure it
		// to skip auth for specific servers or paths
		assert.Equal(t, http.StatusOK, w.Code)

		// The issue is that while gRPC has SkipsAuthenticationServer interface,
		// the HTTP middleware has no equivalent mechanism for the gRPC gateway
	})

	// Test 3: Demonstrate the limitation with gRPC gateway setup
	t.Run("gRPC gateway server skip mechanism not exposed at HTTP layer", func(t *testing.T) {
		// Create gRPC server with auth skip option for specific servers
		skipServer := &mockSkippableServer{shouldSkip: true}

		grpcServer := grpc.NewServer(
			grpc.ChainUnaryInterceptor(
				authmiddlewaregrpc.ClientTokenAuthenticationInterceptor(
					logger,
					store,
					authmiddlewaregrpc.WithServerSkipsAuthentication(skipServer),
				),
			),
		)
		defer grpcServer.Stop()

		// Create listener
		listener, err := net.Listen("tcp", "localhost:0")
		require.NoError(t, err)
		defer listener.Close()

		// Start server
		go func() {
			_ = grpcServer.Serve(listener)
		}()

		time.Sleep(100 * time.Millisecond)

		// Create client connection
		conn, err := grpc.NewClient(
			listener.Addr().String(),
			grpc.WithInsecure(),
		)
		require.NoError(t, err)
		defer conn.Close()

		// Now create an HTTP middleware layer (gRPC gateway)
		mux := runtime.NewServeMux()
		httpMiddleware := authmiddlewarehttp.NewHTTPMiddleware(config.AuthenticationSession{
			Domain: "localhost",
		})

		// The HTTP middleware doesn't have access to the server skip configuration
		// It can't skip auth for the specific servers that should be skipped
		// This means all HTTP routes go through authentication checks

		handler := httpMiddleware.Handler(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			mux.ServeHTTP(w, r)
		}))

		req := httptest.NewRequest("GET", "http://localhost/auth/v1/callback", nil)
		w := httptest.NewRecorder()

		handler.ServeHTTP(w, req)

		// The problem: there's no way to tell the HTTP middleware to skip auth
		// for the OIDC callback endpoint (which is handled by a SkipsAuthenticationServer)
		// So even though the gRPC server can skip auth, the HTTP layer can't bypass it
	})
}

// TestRegression_BrowserSessionAuth tests that browser-based authentication
// using HTTP cookies fails because of the two bugs above combined.
func TestRegression_BrowserSessionAuth(t *testing.T) {
	logger := zaptest.NewLogger(t)
	store := memory.NewStore()

	// Create a valid token
	clientToken, _, err := store.CreateAuthentication(
		context.Background(),
		&authn.CreateAuthenticationRequest{Method: authrpc.Method_METHOD_TOKEN},
	)
	require.NoError(t, err)

	// Test: Browser sends token in cookie, but it's not properly extracted
	t.Run("browser session with cookie fails due to combined bugs", func(t *testing.T) {
		// Simulate browser request with token in HTTP cookie
		req := httptest.NewRequest("GET", "http://localhost/api/v1/flags", nil)
		req.AddCookie(&http.Cookie{
			Name:  middlewarecommon.TokenCookieKey,
			Value: clientToken,
		})

		// HTTP middleware wraps the gRPC gateway
		httpMiddleware := authmiddlewarehttp.NewHTTPMiddleware(config.AuthenticationSession{
			Domain: "localhost",
		})

		// The HTTP cookie forwarding has a bug (token gets overwritten in metadata)
		// AND the HTTP middleware has no skip mechanism for specific servers

		// When the HTTP request reaches the gRPC layer via gateway,
		// the cookie should be converted to gRPC metadata, but the bug in
		// ForwardCookies prevents this from working correctly

		// The metadata forwarding function from internal/server/authn/method/http.go
		// has this bug:
		// ```
		// for _, key := range []string{stateCookieKey, tokenCookieKey} {
		//     if cookie, err := req.Cookie(key); err == nil {
		//         md[stateCookieKey] = []string{cookie.Value}  // BUG: always uses stateCookieKey!
		//     }
		// }
		// ```
		// This causes the token cookie to be stored under the wrong key

		w := httptest.NewRecorder()
		wrappedHandler := httpMiddleware.Handler(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			// Verify the browser sent the cookie
			cookie, err := r.Cookie(middlewarecommon.TokenCookieKey)
			assert.NoError(t, err)
			assert.Equal(t, clientToken, cookie.Value)

			// But when converted to gRPC metadata, it would be misplaced
			// due to the bug in ForwardCookies function
			w.WriteHeader(http.StatusOK)
		}))

		wrappedHandler.ServeHTTP(w, req)
		assert.Equal(t, http.StatusOK, w.Code)

		// The test demonstrates that while the browser properly sends the token
		// in a cookie, the authentication system fails to properly extract it
		// and forward it to the gRPC layer
	})
}

// TestRegression_ExpiredTokenCleanup tests edge cases with token expiration
// and the interaction between cookie-based tokens and the authentication system.
func TestRegression_ExpiredTokenCleanup(t *testing.T) {
	logger := zaptest.NewLogger(t)
	store := memory.NewStore()

	t.Run("expired token in cookie is properly rejected", func(t *testing.T) {
		// Create an expired token
		expiredToken, _, err := store.CreateAuthentication(
			context.Background(),
			&authn.CreateAuthenticationRequest{
				Method:    authrpc.Method_METHOD_TOKEN,
				ExpiresAt: timestamppb.New(time.Now().UTC().Add(-time.Hour)),
			},
		)
		require.NoError(t, err)

		// Verify it fails in gRPC interceptor
		ctx := metadata.NewIncomingContext(
			context.Background(),
			metadata.MD{
				"grpcgateway-cookie": []string{fmt.Sprintf("flipt_client_token=%s", expiredToken)},
			},
		)

		handler := func(ctx context.Context, req interface{}) (interface{}, error) {
			return nil, nil
		}

		interceptor := authmiddlewaregrpc.ClientTokenAuthenticationInterceptor(logger, store)
		_, err = interceptor(ctx, nil, &grpc.UnaryServerInfo{Server: &grpc.Server{}}, handler)

		// Expired token should be rejected
		assert.Error(t, err)
		assert.Equal(t, authmiddlewaregrpc.ErrUnauthenticated, err)
	})
}

